import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class SecureServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response)
            throws ServletException, IOException {
        String userInput = request.getParameter("input");

        // Sanitize user input to prevent XSS attacks
        String sanitizedInput = sanitizeInput(userInput);

        String output = "<p>User input: " + sanitizedInput + "</p>";

        response.setContentType("text/html");
        PrintWriter out = response.getWriter();
        out.println("<html><body>");
        out.println(output);
        out.println("</body></html>");
    }

    private String sanitizeInput(String input) {
        // Implement proper input sanitization logic here
        // For example, you can use libraries like OWASP Java HTML Sanitizer or ESAPI for input validation and output encoding

        // This is just a basic example of escaping special characters
        return input != null ? input.replace("<", "&lt;").replace(">", "&gt;") : "";
    }
}

